class Solution:
    def findIntersectionValues(self, nums1, nums2):
        answer1 = 0
        for x in nums1:
            found = False
            for y in nums2:
                if x == y:
                    found = True
                    break
            if found:
                answer1 += 1
        answer2 = 0
        for y in nums2:
            found = False
            for x in nums1:
                if y == x:
                    found = True
                    break
            if found:
                answer2 += 1
        return [answer1, answer2]

